@* Displays a single task card with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftClicked">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightClicked">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveLeftClicked() => await OnMoveLeft.InvokeAsync();
    private async Task MoveRightClicked() => await OnMoveRight.InvokeAsync();
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <div class="text-danger small mt-1">@error</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        saving = true;
        error = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@* Summary stats bar: total, per-column counts, overdue *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div>
        <strong>Overdue:</strong>
        <span class="@(OverdueCount > 0 ? "text-danger fw-bold" : "")">@OverdueCount</span>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@* Client-side search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTextChanged.InvokeAsync(value);
    }
}

@* A single Kanban column displaying task cards and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, -1))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, 1))" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    /// Direction: -1 = left, +1 = right. Value is (taskId, direction).
    [Parameter] public EventCallback<(int TaskId, int Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

