namespace sv_6a16553dee5b46049902a4a16e9c5836.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@page "/board"
@rendermode InteractiveServer
@using sv_6a16553dee5b46049902a4a16e9c5836.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <SearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var column = columns[i];
            var columnTasks = FilteredTasksForColumn(column);
            <KanbanColumn ColumnName="@column"
                          Tasks="columnTasks"
                          ShowMoveLeft="i > 0"
                          ShowMoveRight="i < columns.Length - 1"
                          OnMoveTask="HandleMoveTask"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> FilteredTasksForColumn(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task HandleMoveTask((int TaskId, int Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = currentIndex + move.Direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
        return Task.CompletedTask;
    }
}

