+    </div>
+}
+
+@code {
+    private static readonly string[] columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> allTasks = [];
+    private string searchText = "";
+    private bool loading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        loading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            loading = false;
+        }
+    }
+
+    private List<TaskItem> FilteredTasksForColumn(string status)
+    {
+        var query = allTasks.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(searchText))
+        {
+            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
+        }
+        return query.ToList();
+    }
+
+    private async Task HandleMoveTask((int TaskId, int Direction) move)
+    {
+        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
+        if (task is null) return;
+
+        var currentIndex = Array.IndexOf(columns, task.Status);
+        var newIndex = currentIndex + move.Direction;
+        if (newIndex < 0 || newIndex >= columns.Length) return;
+
+        var newStatus = columns[newIndex];
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            // Update local state
+            allTasks = allTasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private Task HandleTaskCreated(TaskItem task)
+    {
+        allTasks.Add(task);
+        return Task.CompletedTask;
+    }
+}
